diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..b7cc62c85c3a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2225,6 +2225,70 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
   Value *Op0 = I.getOperand(0);
   Value *Op1 = I.getOperand(1);
   Type *Ty = I.getType();
+
+  auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0);
+  auto *MinMax1 = dyn_cast<MinMaxIntrinsic>(Op1);
+  if (MinMax0 && MinMax1 &&
+      MinMax0->getIntrinsicID() == MinMax1->getIntrinsicID()) {
+    // Both operands are same kind of min/max.
+    // Try to match sub(smin(A+1, B), smin(A, B)) -> icmp slt A, B ? 1 : 0
+    // and similarly for umin.
+    Value *A, *B;
+    const APInt *C;
+    auto MatchAddOrDisjointOr = [&](Value *V) -> bool {
+      return match(V, m_OneUse(m_NSWAdd(m_Value(A), m_APInt(C)))) ||
+             match(V, m_OneUse(m_DisjointOr(m_Value(A), m_APInt(C))));
+    };
+    // For unsigned, need NUW add.
+    auto MatchNUWAddOrDisjointOr = [&](Value *V) -> bool {
+      return match(V, m_OneUse(m_NUWAdd(m_Value(A), m_APInt(C)))) ||
+             match(V, m_OneUse(m_DisjointOr(m_Value(A), m_APInt(C))));
+    };
+    if (MinMax0->isSigned()) {
+      // Match sub(smin(A+1, B), smin(A, B))
+      if (match(Op0, m_c_SMin(m_Value(B), m_CombineOr(
+                  m_OneUse(m_NSWAdd(m_Value(A), m_APInt(C))),
+                  m_OneUse(m_DisjointOr(m_Value(A), m_APInt(C)))))) &&
+          match(Op1, m_c_SMin(m_Specific(A), m_Specific(B))) &&
+          *C == 1 && Op1->hasOneUse()) {
+        Value *Cmp = Builder.CreateICmpSLT(A, B);
+        return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                         ConstantInt::get(Ty, 0));
+      }
+      // Swapped order: sub(smin(A,B), smin(A+1,B))
+      if (match(Op1, m_c_SMin(m_Value(B), m_CombineOr(
+                  m_OneUse(m_NSWAdd(m_Value(A), m_APInt(C))),
+                  m_OneUse(m_DisjointOr(m_Value(A), m_APInt(C)))))) &&
+          match(Op0, m_c_SMin(m_Specific(A), m_Specific(B))) &&
+          *C == 1 && Op0->hasOneUse()) {
+        // sub(smin(A,B), smin(A+1,B)) -> icmp slt A, B ? -1 : 0
+        Value *Cmp = Builder.CreateICmpSLT(A, B);
+        return SelectInst::Create(Cmp, ConstantInt::get(Ty, -1),
+                                         ConstantInt::get(Ty, 0));
+      }
+    } else {
+      // umin
+      if (match(Op0, m_c_UMin(m_Value(B), m_CombineOr(
+                  m_OneUse(m_NUWAdd(m_Value(A), m_APInt(C))),
+                  m_OneUse(m_DisjointOr(m_Value(A), m_APInt(C)))))) &&
+          match(Op1, m_c_UMin(m_Specific(A), m_Specific(B))) &&
+          *C == 1 && Op1->hasOneUse()) {
+        Value *Cmp = Builder.CreateICmpULT(A, B);
+        return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                         ConstantInt::get(Ty, 0));
+      }
+      if (match(Op1, m_c_UMin(m_Value(B), m_CombineOr(
+                  m_OneUse(m_NUWAdd(m_Value(A), m_APInt(C))),
+                  m_OneUse(m_DisjointOr(m_Value(A), m_APInt(C)))))) &&
+          match(Op0, m_c_UMin(m_Specific(A), m_Specific(B))) &&
+          *C == 1 && Op0->hasOneUse()) {
+        Value *Cmp = Builder.CreateICmpULT(A, B);
+        return SelectInst::Create(Cmp, ConstantInt::get(Ty, -1),
+                                         ConstantInt::get(Ty, 0));
+      }
+    }
+  }
+
   auto *MinMax = dyn_cast<MinMaxIntrinsic>(Op1);
   if (!MinMax)
     return nullptr;
@@ -2265,7 +2329,6 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,

   return nullptr;
 }
